/* P-Code VM Debugger panel styles */

.debugger {
    display: flex;
    flex-direction: column;
    flex: 1;
    overflow: hidden;
    min-height: 0;
}

/* Control bar */
.control-bar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 16px;
    border-bottom: 1px solid var(--surface1);
    background: var(--mantle);
    flex-shrink: 0;
}

.btn {
    font-family: var(--mono);
    font-size: 13px;
    padding: 4px 12px;
    border: 1px solid var(--surface2);
    border-radius: 4px;
    cursor: pointer;
    background: var(--surface0);
    color: var(--text);
    transition: background 0.15s;
}

.btn:hover:not(:disabled) {
    background: var(--surface1);
}

.btn:disabled {
    opacity: 0.4;
    cursor: default;
}

.btn-reset {
    color: var(--red);
    border-color: var(--red);
}

.btn-step {
